import { useMemo, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import quizzes from "../data/quizzes";

function QuizAttempt() {
  const { id } = useParams();
  const navigate = useNavigate();
  const quiz = useMemo(() => quizzes.find((q) => q.id === Number(id)), [id]);

  const [answers, setAnswers] = useState({});

  if (!quiz) {
    return <div style={{ padding: "30px" }}>Quiz not found.</div>;
  }

  const handleOptionChange = (questionId, selectedOption) => {
    setAnswers((prev) => ({
      ...prev,
      [questionId]: selectedOption,
    }));
  };

  const handleSubmit = () => {
    let score = 0;

    quiz.questions.forEach((question) => {
      if (answers[question.id] === question.correctAnswer) {
        score += 1;
      }
    });

    navigate("/quiz-result", {
      state: {
        title: quiz.title,
        score,
        total: quiz.questions.length,
      },
    });
  };

  return (
    <div style={{ padding: "30px", color: "black" }}>
      <h1>{quiz.title}</h1>
      <p><strong>Subject:</strong> {quiz.subject}</p>
      <p><strong>Video:</strong> {quiz.videoTitle}</p>

      <div style={{ marginTop: "20px" }}>
        {quiz.questions.map((question, index) => (
          <div
            key={question.id}
            style={{
              marginBottom: "20px",
              padding: "15px",
              border: "1px solid #ddd",
              borderRadius: "8px",
              backgroundColor: "white",
            }}
          >
            <h3>
              {index + 1}. {question.questionText}
            </h3>

            {question.options.map((option) => (
              <div key={option} style={{ marginTop: "8px" }}>
                <label>
                  <input
                    type="radio"
                    name={`question-${question.id}`}
                    value={option}
                    checked={answers[question.id] === option}
                    onChange={() => handleOptionChange(question.id, option)}
                  />
                  {" "}
                  {option}
                </label>
              </div>
            ))}
          </div>
        ))}
      </div>

      <button
        onClick={handleSubmit}
        style={{
          padding: "12px 18px",
          cursor: "pointer",
        }}
      >
        Submit Quiz
      </button>
    </div>
  );
}

export default QuizAttempt;
